   211→    let sampleSize: number;
   212→    const recommendations: string[] = [];
   213→
   214→    switch (config.testType) {
   215→      case 'ttest':
   216→        // Cohen's d effect size for t-test
   217→        sampleSize = Math.ceil(16 / (config.effectSize * config.effectSize));
   218→        if (config.effectSize < 0.2) {
   219→          recommendations.push('Small effect size detected. Consider increasing sample size for better power.');
   220→        }
   221→        break;
   222→
   223→      case 'anova':
   224→        const groups = config.groups || 2;
   225→        sampleSize = Math.ceil((groups * 16) / (config.effectSize * config.effectSize));
   226→        recommendations.push(`ANOVA with ${groups} groups. Consider counterbalancing if possible.`);
   227→        break;
   228→
   229→      case 'correlation':
   230→        sampleSize = Math.ceil(8 / (config.effectSize * config.effectSize) + 3);
   231→        if (sampleSize < 30) {
   232→          recommendations.push('Consider minimum sample size of 30 for correlation analysis.');
   233→        }
   234→        break;
   235→
   236→      case 'chi-square':
   237→        sampleSize = Math.ceil(16 / (config.effectSize * config.effectSize));
   238→        recommendations.push('Ensure expected cell frequencies are at least 5 for chi-square test.');
   239→        break;
   240→
   241→      case 'regression':
   242→        const predictors = config.groups || 1;
   243→        sampleSize = Math.ceil(104 + predictors);
   244→        recommendations.push(`Multiple regression with ${predictors} predictor(s). Follow 10:1 rule for stable estimates.`);
   245→        break;
   246→
   247→      default:
   248→        throw new Error(`Unsupported test type: ${config.testType}`);
   249→    }
   250→
   251→    // Adjust for desired power
   252→    const powerAdjustment = Math.log(power / (1 - power)) / Math.log(4);
   253→    sampleSize = Math.ceil(sampleSize * (1 + powerAdjustment));
   254→
   255→    // Minimum sample size recommendations
   256→    if (sampleSize < 20) {
   257→      recommendations.push('Consider minimum sample size of 20 for reliable results.');
   258→      sampleSize = Math.max(sampleSize, 20);
   259→    }
   260→
   261→    return {
   262→      sampleSize,
   263→      power,
   264→      effectSize: config.effectSize,
   265→      testConfig: config,
   266→      recommendations,
   267→    };
   268→  }
   269→
   270→  // Type-safe condition builder
   271→  conditions<T = Record<string, unknown>>(): ConditionBuilder<T> {
   272→    return new ConditionBuilderImpl<T>();
   273→  }
   274→
   275→  // Type-safe trial builder
   276→  trial<TContext = Record<string, unknown>>(): TrialBuilder<TContext> {
   277→    return new TrialBuilderImpl<TContext>();
   278→  }
   279→
   280→  // Add timeline to experiment
   281→  addTimeline(timeline: Timeline): this {
   282→    this.timelines.push(timeline);
   283→    return this;
   284→  }
   285→
   286→  // Experiment options
   287→  fullScreen(enabled: boolean = true): this {
   288→    this.experimentOptions.fullScreen = enabled;
   289→    return this;
   290→  }
   291→
   292→  backgroundColor(color: string): this {
   293→    // Basic color validation
   294→    const colorRegex = /^(#[0-9a-fA-F]{3,8}|rgb\(.*\)|rgba\(.*\)|hsl\(.*\)|hsla\(.*\)|[a-zA-Z]+)$/;
   295→    if (!colorRegex.test(color)) {
   296→      throw new Error(`Invalid color format: ${color}`);
   297→    }
   298→    this.experimentOptions.backgroundColor = color;
   299→    return this;
   300→  }
   301→
   302→  cursor(cursorType: string): this {
   303→    const validCursors = [
   304→      'auto', 'default', 'none', 'pointer', 'wait', 'text', 'crosshair', 'move', 'help'
   305→    ];
   306→    if (!validCursors.includes(cursorType)) {
   307→      throw new Error(`Invalid cursor type: ${cursorType}. Must be one of: ${validCursors.join(', ')}`);
   308→    }
   309→    this.experimentOptions.cursor = cursorType;
   310→    return this;
   311→  }
   312→
   313→  // Compiler options
   314→  strict(enabled: boolean = true): this {
   315→    this.compilerOptions.strict = enabled;
   316→    return this;
   317→  }
   318→
   319→  optimize(enabled: boolean = true): this {
   320→    this.compilerOptions.optimize = enabled;
   321→    return this;
   322→  }
   323→
   324→  enableVerification(enabled: boolean = true): this {
   325→    this.compilerOptions.enableVerification = enabled;
   326→    return this;
   327→  }
   328→
   329→  includeDebugInfo(enabled: boolean = true): this {
   330→    this.compilerOptions.includeDebugInfo = enabled;
   331→    return this;
   332→  }
   333→
   334→  // Build and validate experiment
   335→  build(): Experiment {
   336→    // Validate experiment configuration
   337→    if (this.experimentOptions.metadata) {
   338→      ExperimentConfigSchema.parse(this.experimentOptions.metadata);
   339→    }
   340→
   341→    if (this.timelines.length === 0) {
   342→      throw new Error('Experiment must have at least one timeline. Use trial() or addTimeline() to add content.');
   343→    }
   344→
   345→    // Create experiment
   346→    const experiment = new Experiment('built-experiment', this.experimentOptions);
   347→    experiment.timeline(this.timelines);
   348→
   349→    return experiment;
   350→  }
   351→
   352→  // Compile to FZB binary format
   353→  async compile(): Promise<CompilerResult> {
   354→    const experiment = this.build();
   355→    const compiler = new ForgeScriptCompiler(this.compilerOptions);
   356→    return compiler.compile(experiment);
   357→  }
   358→
   359→  // Validate without building
   360→  validate(): { valid: boolean; errors: string[] } {
   361→    const errors: string[] = [];
   362→
   363→    try {
   364→      // Validate metadata
   365→      if (this.experimentOptions.metadata) {
   366→        ExperimentConfigSchema.parse(this.experimentOptions.metadata);
   367→      }
   368→    } catch (error) {
   369→      if (error instanceof z.ZodError) {
   370→        errors.push(...error.errors.map(e => e.message));
   371→      }
   372→    }
   373→
   374→    // Check for timelines
   375→    if (this.timelines.length === 0) {
   376→      errors.push('Experiment must have at least one timeline');
   377→    }
   378→
   379→    // Validate power analysis if present
   380→    if (this.powerAnalysis) {
   381→      try {
   382→        PowerAnalysisSchema.parse(this.powerAnalysis);
   383→      } catch (error) {
   384→        if (error instanceof z.ZodError) {
   385→          errors.push(...error.errors.map(e => `Power analysis: ${e.message}`));
   386→        }
   387→      }
   388→    }
   389→
   390→    return {
   391→      valid: errors.length === 0,
   392→      errors,
   393→    };
   394→  }
   395→
   396→  // Create common experiment patterns
   397→  static stroopTask(): FluentExperimentBuilder {
   398→    return new FluentExperimentBuilder('stroop-task')
   399→      .title('Stroop Task')
   400→      .description('Classic Stroop color-word interference task')
   401→      .version('1.0.0')
   402→      .tags(['attention', 'cognitive-control', 'stroop']);
   403→  }
   404→
   405→  static simpleRT(): FluentExperimentBuilder {
   406→    return new FluentExperimentBuilder('simple-rt')
   407→      .title('Simple Reaction Time')
   408→      .description('Simple reaction time measurement task')
   409→      .version('1.0.0')
   410→      .tags(['reaction-time', 'simple-rt']);
   411→  }
   412→
   413→  static choiceRT(): FluentExperimentBuilder {
   414→    return new FluentExperimentBuilder('choice-rt')
   415→      .title('Choice Reaction Time')
   416→      .description('Choice reaction time with multiple response options')
   417→      .version('1.0.0')
   418→      .tags(['reaction-time', 'choice-rt', 'decision-making']);
   419→  }
   420→}
   421→
   422→// Implementation classes for builders
   423→class ConditionBuilderImpl<T = Record<string, unknown>> implements ConditionBuilder<T> {
   424→  private factors: Record<string, unknown[]> = {};
   425→  private repetitions = 1;
   426→  private shouldRandomize = false;
   427→  private randomSeed?: number;
   428→  private blockingFactor?: string;
   429→
   430→  factor<K extends string, V>(name: K, values: V[]): ConditionBuilder<T & Record<K, V>> {
   431→    if (values.length === 0) {
   432→      throw new Error(`Factor '${name}' must have at least one value`);
   433→    }
   434→    this.factors[name] = values;
   435→    return this as any;
   436→  }
   437→
   438→  repeat(count: number): ConditionBuilder<T> {
   439→    if (count < 1) {
   440→      throw new Error('Repeat count must be at least 1');
   441→    }
   442→    this.repetitions = count;
   443→    return this;
   444→  }
   445→
   446→  randomize(seed?: number): ConditionBuilder<T> {
   447→    this.shouldRandomize = true;
   448→    this.randomSeed = seed;
   449→    return this;
   450→  }
   451→
   452→  block<K extends keyof T>(factor: K): ConditionBuilder<T> {
   453→    this.blockingFactor = factor as string;
   454→    return this;
   455→  }
   456→
   457→  build(): Array<T & { _trial: number; _block?: number }> {
   458→    // Generate all combinations
   459→    const factorNames = Object.keys(this.factors);
   460→    if (factorNames.length === 0) {
   461→      throw new Error('At least one factor must be defined');
   462→    }
   463→
   464→    const combinations = this.generateCombinations(factorNames, this.factors);
   465→    
   466→    // Repeat combinations
   467→    const conditions: Array<T & { _trial: number; _block?: number }> = [];
   468→    for (let rep = 0; rep < this.repetitions; rep++) {
   469→      combinations.forEach((combo) => {
   470→        conditions.push({
   471→          ...combo,
   472→          _trial: conditions.length,
   473→        } as T & { _trial: number; _block?: number });
   474→      });
   475→    }
   476→
   477→    // Apply blocking
   478→    if (this.blockingFactor && this.blockingFactor in this.factors) {
   479→      this.applyBlocking(conditions, this.blockingFactor);
   480→    }
   481→
   482→    // Randomize if requested
   483→    if (this.shouldRandomize) {
   484→      this.randomizeConditions(conditions, this.randomSeed);
   485→    }
   486→
   487→    return conditions;
   488→  }
   489→
   490→  private generateCombinations(factorNames: string[], factors: Record<string, unknown[]>): T[] {
   491→    const result: T[] = [];
   492→    
   493→    const generate = (index: number, current: Record<string, unknown>) => {
   494→      if (index === factorNames.length) {
   495→        result.push(current as T);
   496→        return;
   497→      }
   498→      
   499→      const factorName = factorNames[index];
   500→      if (!factorName) return;
   501→      
   502→      const values = factors[factorName];
   503→      if (!values) return;
   504→      
   505→      for (const value of values) {
   506→        generate(index + 1, { ...current, [factorName]: value });
   507→      }
   508→    };
   509→    
   510→    generate(0, {});
   511→    return result;
   512→  }
   513→
   514→  private applyBlocking(conditions: Array<T & { _trial: number; _block?: number }>, blockingFactor: string): void {
   515→    const blocks = new Map<unknown, number>();
   516→    let blockIndex = 0;
   517→
   518→    conditions.forEach(condition => {
   519→      const blockValue = (condition as any)[blockingFactor];
   520→      if (!blocks.has(blockValue)) {
   521→        blocks.set(blockValue, blockIndex++);
   522→      }
   523→      condition._block = blocks.get(blockValue);
   524→    });
   525→  }
   526→
   527→  private randomizeConditions(conditions: Array<T & { _trial: number; _block?: number }>, seed?: number): void {
   528→    // Simple pseudo-random shuffle
   529→    // In a real implementation, this would use a proper seeded random number generator
   530→    const rng = seed ? this.seededRandom(seed) : Math.random;
   531→    
   532→    for (let i = conditions.length - 1; i > 0; i--) {
   533→      const j = Math.floor(rng() * (i + 1));
   534→      const temp = conditions[i];
   535→      conditions[i] = conditions[j]!;
   536→      conditions[j] = temp!;
   537→    }
   538→
   539→    // Update trial numbers
   540→    conditions.forEach((condition, index) => {
   541→      condition._trial = index;
   542→    });
   543→  }
   544→
   545→  private seededRandom(seed: number): () => number {
   546→    return () => {
   547→      seed = (seed * 9301 + 49297) % 233280;
   548→      return seed / 233280;
   549→    };
   550→  }
   551→}
   552→
   553→class TrialBuilderImpl<TContext = Record<string, unknown>> implements TrialBuilder<TContext> {
   554→  private timeline: Timeline;
   555→
   556→  constructor() {
   557→    this.timeline = new Timeline(`trial-${Date.now()}`);
   558→  }
   559→
   560→  fixation(duration: number = 1000, symbol: string = '+'): TrialBuilder<TContext> {
   561→    const stimulus = new TextStimulus(`fixation-${Date.now()}`, symbol, {
   562→      fontSize: 48,
   563→      color: 'black',
   564→      position: { x: 0, y: 0 },
   565→      duration,
   566→    });
   567→    this.timeline.add(stimulus);
   568→    return this;
   569→  }
   570→
   571→  text(content: string | ((ctx: TContext) => string), duration?: number): TrialBuilder<TContext> {
   572→    const stimulus = new TextStimulus(`text-${Date.now()}`, content as any, {
   573→      fontSize: 24,
   574→      color: 'black',
   575→      position: { x: 0, y: 0 },
   576→      duration,
   577→    });
   578→    this.timeline.add(stimulus);
   579→    return this;
   580→  }
   581→
   582→  image(url: string, duration?: number): TrialBuilder<TContext> {
   583→    const stimulus = new ImageStimulus(`image-${Date.now()}`, url, {
   584→      duration,
   585→      position: { x: 0, y: 0 },
   586→    });
   587→    this.timeline.add(stimulus);
   588→    return this;
   589→  }
   590→
   591→  audio(url: string): TrialBuilder<TContext> {
   592→    const stimulus = new AudioStimulus(`audio-${Date.now()}`, url, {
   593→      autoplay: true,
   594→    });
   595→    this.timeline.add(stimulus);
   596→    return this;
   597→  }
   598→
   599→  video(url: string, duration?: number): TrialBuilder<TContext> {
   600→    const stimulus = new VideoStimulus(`video-${Date.now()}`, url, {
   601→      duration,
   602→      autoplay: true,
   603→      position: { x: 0, y: 0 },
   604→    });
   605→    this.timeline.add(stimulus);
   606→    return this;
   607→  }
   608→
   609→  keyboard(keys?: string[], timeout?: number): TrialBuilder<TContext> {
   610→    const response = new KeyboardResponse(`keyboard-${Date.now()}`, {
   611→      allowedKeys: keys,
   612→      timeout,
   613→    });
   614→    this.timeline.add(response);
   615→    return this;
   616→  }
   617→
   618→  mouse(timeout?: number): TrialBuilder<TContext> {
   619→    const response = new MouseResponse(`mouse-${Date.now()}`, {
   620→      timeout,
   621→    });
   622→    this.timeline.add(response);
   623→    return this;
   624→  }
   625→
   626→  touch(timeout?: number): TrialBuilder<TContext> {
   627→    const response = new TouchResponse(`touch-${Date.now()}`, {
   628→      timeout,
   629→    });
   630→    this.timeline.add(response);
   631→    return this;
   632→  }
   633→
   634→  wait(duration: number): TrialBuilder<TContext> {
   635→    const waitEvent = new WaitEvent(`wait-${Date.now()}`, duration);
   636→    this.timeline.add(waitEvent);
   637→    return this;
   638→  }
   639→
   640→  when(condition: (ctx: TContext) => boolean, then: (builder: TrialBuilder<TContext>) => void): TrialBuilder<TContext> {
   641→    const subBuilder = new TrialBuilderImpl<TContext>();
   642→    then(subBuilder);
   643→    const trueTimeline = subBuilder.build();
   644→    
   645→    const conditionalEvent = new ConditionalEvent(
   646→      `conditional-${Date.now()}`,
   647→      condition as any,
   648→      trueTimeline
   649→    );
   650→    this.timeline.add(conditionalEvent);
   651→    return this;
   652→  }
   653→
   654→  loop(count: number | ((ctx: TContext) => number), body: (builder: TrialBuilder<TContext>) => void): TrialBuilder<TContext> {
   655→    const subBuilder = new TrialBuilderImpl<TContext>();
   656→    body(subBuilder);
   657→    const loopTimeline = subBuilder.build();
   658→    
   659→    // For now, use a fixed count if it's a function
   660→    const iterations = typeof count === 'function' ? 10 : count;
   661→    
   662→    const loopEvent = new LoopEvent(
   663→      `loop-${Date.now()}`,
   664→      iterations,
   665→      loopTimeline
   666→    );
   667→    this.timeline.add(loopEvent);
   668→    return this;
   669→  }
   670→
   671→  setData<K extends string, V>(key: K, value: V | ((ctx: TContext) => V)): TrialBuilder<TContext & Record<K, V>> {
   672→    const dataCollector = (ctx: TimelineContext) => {
   673→      const val = typeof value === 'function' ? (value as any)(ctx) : value;
   674→      return { [key]: val };
   675→    };
   676→    
   677→    const dataEvent = new DataEvent(`data-${Date.now()}`, dataCollector);
   678→    this.timeline.add(dataEvent);
   679→    return this as any;
   680→  }
   681→
   682→  build(): Timeline {
   683→    return this.timeline;
   684→  }
   685→}
   686→
   687→// Export convenience function
   688→export function experiment(id: string): FluentExperimentBuilder {
   689→  return new FluentExperimentBuilder(id);
   690→}
   691→
   692→// Export type-safe condition and trial builders
   693→export function conditions<T = Record<string, unknown>>(): ConditionBuilder<T> {
   694→  return new ConditionBuilderImpl<T>();
   695→}
   696→
   697→export function trial<TContext = Record<string, unknown>>(): TrialBuilder<TContext> {
   698→  return new TrialBuilderImpl<TContext>();
   699→}

