/**
 * ForgeScript Compiler - Compile-time validation and FZB binary format generation
 */

// import { z } from 'zod'; // Will be used for validation schemas
import type { Experiment } from '../core/Experiment.js';
import type { Timeline } from '../core/Timeline.js';
import { Validator, type ValidationResult } from '../serialization/Validator.js';
import { Serializer } from '../serialization/Serializer.js';

export interface CompilerOptions {
  /** Enable strict type checking */
  strict?: boolean;
  /** Target FZB binary format version */
  targetVersion?: string;
  /** Enable optimization passes */
  optimize?: boolean;
  /** Enable formal verification */
  enableVerification?: boolean;
  /** Include debug information */
  includeDebugInfo?: boolean;
  /** Maximum compilation time in milliseconds */
  timeout?: number;
}

export interface CompilerResult {
  /** Whether compilation succeeded */
  success: boolean;
  /** Validation result from compiler */
  validation: ValidationResult;
  /** Compiled FZB binary data */
  binary?: Uint8Array;
  /** Compilation metadata */
  metadata?: CompilerMetadata;
  /** Compilation errors */
  errors: CompilerError[];
  /** Compilation warnings */
  warnings: CompilerWarning[];
}

export interface CompilerMetadata {
  /** Compilation timestamp */
  compiledAt: number;
  /** Compiler version */
  compilerVersion: string;
  /** Target FZB version */
  targetVersion: string;
  /** Source experiment hash */
  sourceHash: string;
  /** Optimization level applied */
  optimizationLevel: number;
  /** Size of compiled binary */
  binarySize: number;
}

export interface CompilerError {
  code: string;
  message: string;
  severity: 'critical' | 'high' | 'medium' | 'low';
  location?: string;
  suggestion?: string;
}

export interface CompilerWarning {
  code: string;
  message: string;
  location?: string;
  recommendation?: string;
}

export interface FZBHeader {
  /** Magic bytes "FZB\0" */
  magic: Uint8Array;
  /** FZB format version */
  version: number;
  /** Flags for format features */
  flags: number;
  /** Size of metadata section */
  metadataSize: number;
  /** Size of experiment data section */
  dataSize: number;
  /** CRC32 checksum */
  checksum: number;
}

export class ForgeScriptCompiler {
  private static readonly VERSION = '1.0.0';
  private static readonly FZB_MAGIC = new Uint8Array([0x46, 0x5A, 0x42, 0x00]); // "FZB\0"
  private static readonly FZB_VERSION = 1;

  private options: Required<CompilerOptions>;

  constructor(options: CompilerOptions = {}) {
    this.options = {
      strict: false,
      targetVersion: '1.0.0',
      optimize: true,
      enableVerification: false,
      includeDebugInfo: false,
      timeout: 30000, // 30 seconds
      ...options,
    };
  }

  /**
   * Compile an experiment to FZB binary format
   */
  async compile(experiment: Experiment): Promise<CompilerResult> {
    // const startTime = Date.now(); // Can be used for compilation timing
    const errors: CompilerError[] = [];
    const warnings: CompilerWarning[] = [];

    try {
      // Set compilation timeout
      const timeoutPromise = new Promise<never>((_, reject) => {
        setTimeout(() => reject(new Error('Compilation timeout')), this.options.timeout);
      });

      const compilationPromise = this.performCompilation(experiment, errors, warnings);

      const result = await Promise.race([compilationPromise, timeoutPromise]);

      return {
        ...result,
        errors,
        warnings,
      };

    } catch (error) {
      errors.push({
        code: 'COMPILATION_FAILED',
        message: `Compilation failed: ${error}`,
        severity: 'critical',
      });

      return {
        success: false,
        validation: { valid: false, errors: [], warnings: [] },
        errors,
        warnings,
      };
    }
  }

  private async performCompilation(
    experiment: Experiment,
    errors: CompilerError[],
    warnings: CompilerWarning[]
  ): Promise<Omit<CompilerResult, 'errors' | 'warnings'>> {
    // Step 1: Validate experiment structure
    console.log('🔍 Validating experiment structure...');
    const validation = await this.validateExperiment(experiment);

    if (!validation.valid) {
      // Convert validation errors to compiler errors
      validation.errors.forEach(error => {
        errors.push({
          code: error.code,
          message: error.message,
          severity: error.severity,
          location: error.path,
        });
      });
    }

    // Convert validation warnings to compiler warnings
    validation.warnings.forEach(warning => {
      warnings.push({
        code: warning.code,
        message: warning.message,
        location: warning.path,
        recommendation: warning.recommendation,
      });
    });

    // Stop compilation if critical errors found in strict mode
    if (this.options.strict && errors.some(e => e.severity === 'critical')) {
      return {
        success: false,
        validation,
      };
    }

    // Step 2: Perform formal verification if enabled
    if (this.options.enableVerification) {
      console.log('✅ Performing formal verification...');
      await this.performFormalVerification(experiment, errors, warnings);
    }

    // Step 3: Optimize experiment if enabled
    let optimizedExperiment = experiment;
    if (this.options.optimize) {
      console.log('⚡ Optimizing experiment...');
      optimizedExperiment = await this.optimizeExperiment(experiment, warnings);
    }

    // Step 4: Generate FZB binary
    console.log('🔧 Generating FZB binary...');
    const binary = await this.generateFZBBinary(optimizedExperiment);

    // Step 5: Create compilation metadata
    const sourceHash = await this.computeHash(JSON.stringify(experiment.serialize()));
    const metadata: CompilerMetadata = {
      compiledAt: Date.now(),
      compilerVersion: ForgeScriptCompiler.VERSION,
      targetVersion: this.options.targetVersion,
      sourceHash,
      optimizationLevel: this.options.optimize ? 1 : 0,
      binarySize: binary.length,
    };

    console.log(`✨ Compilation completed successfully (${binary.length} bytes)`);

    return {
      success: true,
      validation,
      binary,
      metadata,
    };
  }

  private async validateExperiment(experiment: Experiment): Promise<ValidationResult> {
    const options = {
      strict: this.options.strict,
      checkTiming: true,
      checkAccessibility: true,
      checkPerformance: true,
    };

    return Validator.validateExperiment(experiment, options);
  }

  private async performFormalVerification(
    experiment: Experiment,
    errors: CompilerError[],
    warnings: CompilerWarning[]
  ): Promise<void> {
    // Formal verification checks
    const timelines = experiment.getTimelines();

    // Check for unreachable timelines
    const reachableTimelines = new Set<string>();
    this.markReachableTimelines(timelines, reachableTimelines);

    timelines.forEach((timeline, index) => {
      if (!reachableTimelines.has(timeline.id)) {
        warnings.push({
          code: 'UNREACHABLE_TIMELINE',
          message: `Timeline '${timeline.id}' is unreachable`,
          location: `timelines[${index}]`,
          recommendation: 'Remove unreachable timeline or fix timeline flow',
        });
      }
    });

    // Check for infinite loops
    this.detectInfiniteLoops(timelines, errors);

    // Check for missing dependencies
    this.validateDependencies(experiment, errors);

    // Check for timing constraints
    this.validateTimingConstraints(experiment, errors, warnings);
  }

  private markReachableTimelines(timelines: Timeline[], reachable: Set<string>): void {
    // Mark first timeline as reachable
    if (timelines.length > 0) {
      const firstTimeline = timelines[0];
      if (firstTimeline) {
        reachable.add(firstTimeline.id);
      }
      // This would recursively follow timeline transitions
      // Simplified implementation for now
    }
  }

  private detectInfiniteLoops(timelines: Timeline[], errors: CompilerError[]): void {
    // Simplified cycle detection
    // In a real implementation, this would use graph algorithms
    timelines.forEach(timeline => {
      const options = timeline.getOptions();
      if (options.repeat !== undefined && options.repeat > 10000) {
        errors.push({
          code: 'POTENTIAL_INFINITE_LOOP',
          message: `Timeline '${timeline.id}' has very high repeat count that may cause infinite loop`,
          severity: 'high',
          location: `timeline.${timeline.id}.repeat`,
          suggestion: 'Add explicit termination condition or reduce repeat count',
        });
      }
    });
  }

  private validateDependencies(experiment: Experiment, errors: CompilerError[]): void {
    // Check that all referenced assets exist
    // Check that all response handlers are defined
    // This would be more comprehensive in a real implementation

    const timelines = experiment.getTimelines();
    timelines.forEach(timeline => {
      timeline.getItems().forEach(item => {
        // Check for missing stimulus files
        if ('url' in item && item.url && typeof item.url === 'string') {
          // In a real implementation, this would check if the URL is accessible
          if (item.url.startsWith('missing://')) {
            errors.push({
              code: 'MISSING_ASSET',
              message: `Asset not found: ${item.url}`,
              severity: 'critical',
              location: `item.${item.id}.url`,
              suggestion: 'Ensure the asset file exists and is accessible',
            });
          }
        }
      });
    });
  }

  private validateTimingConstraints(
    experiment: Experiment,
    errors: CompilerError[],
    warnings: CompilerWarning[]
  ): void {
    // Check for timing conflicts
    // Validate that timing requirements can be met
    const timelines = experiment.getTimelines();

    timelines.forEach(timeline => {
      timeline.getItems().forEach(item => {
        // Check for sub-frame durations
        if (item.duration && item.duration < 16.67) {
          warnings.push({
            code: 'SUB_FRAME_DURATION',
            message: `Item '${item.id}' duration (${item.duration}ms) is less than one frame at 60Hz`,
            location: `item.${item.id}.duration`,
            recommendation: 'Consider using frame-based timing for better precision',
          });
        }

        // Check for precision requirements
        if (item.duration && item.duration < 2) {
          errors.push({
            code: 'IMPOSSIBLE_TIMING',
            message: `Item '${item.id}' duration (${item.duration}ms) violates ≤2ms timing precision requirement`,
            severity: 'high',
            location: `item.${item.id}.duration`,
            suggestion: 'Increase duration to at least 2ms or use different timing method',
          });
        }
      });
    });
  }

  private async optimizeExperiment(experiment: Experiment, warnings: CompilerWarning[]): Promise<Experiment> {
    // Optimization passes:
    // 1. Remove unused timelines
    // 2. Combine sequential stimuli
    // 3. Optimize asset loading
    // 4. Minimize serialized size

    // For now, return the original experiment
    // Real optimization would create a new optimized experiment

    warnings.push({
      code: 'OPTIMIZATION_APPLIED',
      message: 'Basic optimization passes applied',
      recommendation: 'Monitor performance to ensure optimization effectiveness',
    });

    return experiment;
  }

  private async generateFZBBinary(experiment: Experiment): Promise<Uint8Array> {
    // Serialize experiment to JSON
    const serialized = Serializer.serialize(experiment, {
      format: 'compact',
      includeMetadata: true,
      includeResponseData: false,
    });

    // Compress the JSON data
    const jsonData = JSON.stringify(serialized);
    const compressedData = await this.compressData(jsonData);

    // Create FZB header
    const header = this.createFZBHeader(compressedData);

    // Combine header and data
    const headerBytes = this.serializeHeader(header);
    const binary = new Uint8Array(headerBytes.length + compressedData.length);
    binary.set(headerBytes, 0);
    binary.set(compressedData, headerBytes.length);

    return binary;
  }

  private createFZBHeader(data: Uint8Array): FZBHeader {
    return {
      magic: ForgeScriptCompiler.FZB_MAGIC,
      version: ForgeScriptCompiler.FZB_VERSION,
      flags: this.options.includeDebugInfo ? 1 : 0,
      metadataSize: 0, // No separate metadata section for now
      dataSize: data.length,
      checksum: this.calculateCRC32(data),
    };
  }

  private serializeHeader(header: FZBHeader): Uint8Array {
    const buffer = new ArrayBuffer(24); // 4 + 4 + 4 + 4 + 4 + 4 bytes
    const view = new DataView(buffer);
    const bytes = new Uint8Array(buffer);

    // Magic bytes
    bytes.set(header.magic, 0);

    // Version (4 bytes, little-endian)
    view.setUint32(4, header.version, true);

    // Flags (4 bytes, little-endian)
    view.setUint32(8, header.flags, true);

    // Metadata size (4 bytes, little-endian)
    view.setUint32(12, header.metadataSize, true);

    // Data size (4 bytes, little-endian)
    view.setUint32(16, header.dataSize, true);

    // Checksum (4 bytes, little-endian)
    view.setUint32(20, header.checksum, true);

    return bytes;
  }

  private async compressData(data: string): Promise<Uint8Array> {
    // Simple compression using TextEncoder for now
    // In a real implementation, this would use proper compression (gzip, brotli, etc.)
    const encoder = new TextEncoder();
    return encoder.encode(data);
  }

  private calculateCRC32(data: Uint8Array): number {
    // Simplified CRC32 calculation
    // In a real implementation, this would use a proper CRC32 algorithm
    let crc = 0;
    for (let i = 0; i < data.length; i++) {
      const byte = data[i];
      if (byte !== undefined) {
        crc = (crc + byte) % 0xFFFFFFFF;
      }
    }
    return crc;
  }

  private async computeHash(data: string): Promise<string> {
    // Simple hash function for now
    // In a real implementation, this would use SHA-256 or similar
    let hash = 0;
    for (let i = 0; i < data.length; i++) {
      const char = data.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash; // Convert to 32-bit integer
    }
    return Math.abs(hash).toString(16);
  }

  /**
   * Decompile FZB binary back to experiment
   */
  async decompile(binary: Uint8Array): Promise<Experiment> {
    // Parse FZB header
    const header = this.parseHeader(binary);

    // Validate magic bytes
    if (!this.validateMagic(header.magic)) {
      throw new Error('Invalid FZB file: magic bytes mismatch');
    }

    // Validate version
    if (header.version !== ForgeScriptCompiler.FZB_VERSION) {
      throw new Error(`Unsupported FZB version: ${header.version}`);
    }

    // Extract and decompress data
    const dataStart = 24; // Header size
    const compressedData = binary.slice(dataStart, dataStart + header.dataSize);

    // Validate checksum
    const actualChecksum = this.calculateCRC32(compressedData);
    if (actualChecksum !== header.checksum) {
      throw new Error('FZB file corruption detected: checksum mismatch');
    }

    // Decompress data
    const jsonData = await this.decompressData(compressedData);

    // Parse and deserialize experiment
    const serialized = JSON.parse(jsonData);
    return Serializer.deserialize(serialized);
  }

  private parseHeader(binary: Uint8Array): FZBHeader {
    if (binary.length < 24) {
      throw new Error('Invalid FZB file: too small');
    }

    const view = new DataView(binary.buffer, binary.byteOffset);

    return {
      magic: binary.slice(0, 4),
      version: view.getUint32(4, true),
      flags: view.getUint32(8, true),
      metadataSize: view.getUint32(12, true),
      dataSize: view.getUint32(16, true),
      checksum: view.getUint32(20, true),
    };
  }

  private validateMagic(magic: Uint8Array): boolean {
    if (magic.length !== 4) return false;
    for (let i = 0; i < 4; i++) {
      if (magic[i] !== ForgeScriptCompiler.FZB_MAGIC[i]) {
        return false;
      }
    }
    return true;
  }

  private async decompressData(data: Uint8Array): Promise<string> {
    // Simple decompression using TextDecoder for now
    const decoder = new TextDecoder();
    return decoder.decode(data);
  }

  /**
   * Get compiler version
   */
  static getVersion(): string {
    return ForgeScriptCompiler.VERSION;
  }

  /**
   * Check if a binary is a valid FZB file
   */
  static isFZBFile(binary: Uint8Array): boolean {
    if (binary.length < 4) return false;

    const magic = binary.slice(0, 4);
    for (let i = 0; i < 4; i++) {
      if (magic[i] !== ForgeScriptCompiler.FZB_MAGIC[i]) {
        return false;
      }
    }
    return true;
  }
}

// Export convenience functions
export async function compileExperiment(
  experiment: Experiment,
  options?: CompilerOptions
): Promise<CompilerResult> {
  const compiler = new ForgeScriptCompiler(options);
  return compiler.compile(experiment);
}

export async function decompileExperiment(binary: Uint8Array): Promise<Experiment> {
  const compiler = new ForgeScriptCompiler();
  return compiler.decompile(binary);
}

