import * as PIXI from 'pixi.js';
import { BaseStimulus, type StimulusOptions } from './BaseStimulus.js';
import type { TimelineContext } from '../core/Timeline.js';
import { 
  sanitizeColorValue, 
  sanitizeFontFamily, 
  sanitizeTextContent 
} from '../utils/security.js';

export interface TextStimulusPixiOptions extends StimulusOptions {
  fontSize?: number;
  fontFamily?: string;
  fontWeight?: string;
  fontStyle?: string;
  color?: string;
  strokeColor?: string;
  strokeThickness?: number;
  dropShadow?: boolean;
  dropShadowColor?: string;
  dropShadowBlur?: number;
  dropShadowAngle?: number;
  dropShadowDistance?: number;
  letterSpacing?: number;
  lineHeight?: number;
  align?: 'left' | 'center' | 'right';
  wordWrap?: boolean;
  wordWrapWidth?: number;
  breakWords?: boolean;
  resolution?: number;
}

export class TextStimulusPixi extends BaseStimulus {
  public readonly id: string;
  private textContent: string | ((context: TimelineContext) => string);
  private textOptions: TextStimulusPixiOptions;
  private textObject?: PIXI.Text;

  constructor(
    id: string,
    text: string | ((context: TimelineContext) => string),
    options: TextStimulusPixiOptions = {}
  ) {
    super(options);
    this.id = id;
    this.textContent = text;
    this.textOptions = {
      fontSize: 24,
      fontFamily: 'Arial',
      fontWeight: 'normal',
      fontStyle: 'normal',
      color: '#FFFFFF',
      align: 'center',
      resolution: window.devicePixelRatio || 1,
      ...options,
    };
  }

  getType(): string {
    return 'TextStimulusPixi';
  }

  async createDisplayObject(): Promise<PIXI.DisplayObject> {
    // Resolve text content if it's a function
    const resolvedText = typeof this.textContent === 'function' 
      ? this.textContent({ clock: (window as any).__psyforgeContext?.clock } as TimelineContext)
      : this.textContent;

    const sanitizedText = sanitizeTextContent(resolvedText);

    // Create text style with sanitized values
    const style = new PIXI.TextStyle({
      fontFamily: this.textOptions.fontFamily ? 
        sanitizeFontFamily(this.textOptions.fontFamily) || 'Arial' : 'Arial',
      fontSize: this.textOptions.fontSize,
      fontWeight: this.textOptions.fontWeight as PIXI.TextStyleFontWeight,
      fontStyle: this.textOptions.fontStyle as PIXI.TextStyleFontStyle,
      fill: this.textOptions.color ? 
        sanitizeColorValue(this.textOptions.color) || '#FFFFFF' : '#FFFFFF',
      align: this.textOptions.align,
      letterSpacing: this.textOptions.letterSpacing,
      lineHeight: this.textOptions.lineHeight,
      wordWrap: this.textOptions.wordWrap,
      wordWrapWidth: this.textOptions.wordWrapWidth,
      breakWords: this.textOptions.breakWords,
    });

    // Add stroke if specified
    if (this.textOptions.strokeColor && this.textOptions.strokeThickness) {
      const sanitizedStroke = sanitizeColorValue(this.textOptions.strokeColor);
      if (sanitizedStroke) {
        style.stroke = { color: sanitizedStroke, width: this.textOptions.strokeThickness };
      }
    }

    // Add drop shadow if specified
    if (this.textOptions.dropShadow) {
      style.dropShadow = {
        color: this.textOptions.dropShadowColor ? 
          sanitizeColorValue(this.textOptions.dropShadowColor) || '#000000' : '#000000',
        blur: this.textOptions.dropShadowBlur || 2,
        angle: this.textOptions.dropShadowAngle || Math.PI / 4,
        distance: this.textOptions.dropShadowDistance || 5,
      };
    }

    // Create text object
    this.textObject = new PIXI.Text({
      text: sanitizedText,
      style,
      resolution: this.textOptions.resolution,
    });

    // Set anchor for centering
    this.textObject.anchor.set(
      this.options.anchor!.x,
      this.options.anchor!.y
    );

    return this.textObject;
  }

  // Fluent API methods
  text(content: string | ((context: TimelineContext) => string)): this {
    this.textContent = content;
    if (this.textObject) {
      const resolvedText = typeof content === 'function' 
        ? content({ clock: (window as any).__psyforgeContext?.clock } as TimelineContext)
        : content;
      this.textObject.text = sanitizeTextContent(resolvedText);
    }
    return this;
  }

  fontSize(size: number): this {
    this.textOptions.fontSize = size;
    if (this.textObject) {
      this.textObject.style.fontSize = size;
    }
    return this;
  }

  fontFamily(family: string): this {
    const sanitized = sanitizeFontFamily(family);
    if (sanitized) {
      this.textOptions.fontFamily = sanitized;
      if (this.textObject) {
        this.textObject.style.fontFamily = sanitized;
      }
    }
    return this;
  }

  color(textColor: string): this {
    const sanitized = sanitizeColorValue(textColor);
    if (sanitized) {
      this.textOptions.color = sanitized;
      if (this.textObject) {
        this.textObject.style.fill = sanitized;
      }
    }
    return this;
  }

  stroke(color: string, thickness: number): this {
    const sanitized = sanitizeColorValue(color);
    if (sanitized) {
      this.textOptions.strokeColor = sanitized;
      this.textOptions.strokeThickness = thickness;
      if (this.textObject) {
        this.textObject.style.stroke = { color: sanitized, width: thickness };
      }
    }
    return this;
  }

  dropShadow(options: {
    color?: string;
    blur?: number;
    angle?: number;
    distance?: number;
  }): this {
    this.textOptions.dropShadow = true;
    if (options.color) {
      const sanitized = sanitizeColorValue(options.color);
      if (sanitized) {
        this.textOptions.dropShadowColor = sanitized;
      }
    }
    if (options.blur !== undefined) this.textOptions.dropShadowBlur = options.blur;
    if (options.angle !== undefined) this.textOptions.dropShadowAngle = options.angle;
    if (options.distance !== undefined) this.textOptions.dropShadowDistance = options.distance;

    if (this.textObject) {
      this.textObject.style.dropShadow = {
        color: this.textOptions.dropShadowColor || '#000000',
        blur: this.textOptions.dropShadowBlur || 2,
        angle: this.textOptions.dropShadowAngle || Math.PI / 4,
        distance: this.textOptions.dropShadowDistance || 5,
      };
    }
    return this;
  }

  align(alignment: 'left' | 'center' | 'right'): this {
    this.textOptions.align = alignment;
    if (this.textObject) {
      this.textObject.style.align = alignment;
    }
    return this;
  }

  wordWrap(enabled: boolean, width?: number): this {
    this.textOptions.wordWrap = enabled;
    if (width !== undefined) {
      this.textOptions.wordWrapWidth = width;
    }
    if (this.textObject) {
      this.textObject.style.wordWrap = enabled;
      if (width !== undefined) {
        this.textObject.style.wordWrapWidth = width;
      }
    }
    return this;
  }

  letterSpacing(spacing: number): this {
    this.textOptions.letterSpacing = spacing;
    if (this.textObject) {
      this.textObject.style.letterSpacing = spacing;
    }
    return this;
  }

  lineHeight(height: number): this {
    this.textOptions.lineHeight = height;
    if (this.textObject) {
      this.textObject.style.lineHeight = height;
    }
    return this;
  }

  // Override position method to work with PIXI coordinates
  position(x: number, y: number): this {
    this.options.position = { x, y };
    if (this.displayObject) {
      this.displayObject.position.set(x, y);
    }
    return this;
  }

  // Animation methods for smooth transitions
  async fadeIn(duration: number = 500): Promise<void> {
    if (!this.displayObject) return;

    this.displayObject.alpha = 0;
    const startAlpha = 0;
    const endAlpha = this.options.opacity || 1;
    const startTime = performance.now();

    return new Promise((resolve) => {
      const animate = () => {
        const elapsed = performance.now() - startTime;
        const progress = Math.min(elapsed / duration, 1);

        if (this.displayObject) {
          this.displayObject.alpha = startAlpha + (endAlpha - startAlpha) * progress;
        }

        if (progress < 1) {
          requestAnimationFrame(animate);
        } else {
          resolve();
        }
      };
      animate();
    });
  }

  async fadeOut(duration: number = 500): Promise<void> {
    if (!this.displayObject) return;

    const startAlpha = this.displayObject.alpha;
    const endAlpha = 0;
    const startTime = performance.now();

    return new Promise((resolve) => {
      const animate = () => {
        const elapsed = performance.now() - startTime;
        const progress = Math.min(elapsed / duration, 1);

        if (this.displayObject) {
          this.displayObject.alpha = startAlpha + (endAlpha - startAlpha) * progress;
        }

        if (progress < 1) {
          requestAnimationFrame(animate);
        } else {
          resolve();
        }
      };
      animate();
    });
  }

  serialize(): Record<string, unknown> {
    return {
      type: 'TextStimulusPixi',
      id: this.id,
      text: typeof this.textContent === 'string' ? this.textContent : '[Function]',
      options: this.textOptions,
    };
  }
}

