   355→// Helper function to generate counterbalanced Stroop conditions
   356→function generateStroopConditions(
   357→  numTrials: number, 
   358→  trialType: 'practice' | 'test',
   359→  blockNumber: number
   360→): StroopCondition[] {
   361→  const words = Object.keys(COLOR_MAP);
   362→  const conditions: StroopCondition[] = [];
   363→  
   364→  // Ensure equal distribution of congruent and incongruent trials
   365→  const halfTrials = Math.floor(numTrials / 2);
   366→  
   367→  // Generate congruent trials
   368→  for (let i = 0; i < halfTrials; i++) {
   369→    const wordIndex = i % words.length;
   370→    const word = words[wordIndex];
   371→    conditions.push({
   372→      word,
   373→      color: word,
   374→      colorHex: COLOR_MAP[word as keyof typeof COLOR_MAP],
   375→      congruent: true,
   376→      trialType,
   377→      blockNumber,
   378→      trialNumber: i + 1
   379→    });
   380→  }
   381→  
   382→  // Generate incongruent trials
   383→  for (let i = 0; i < numTrials - halfTrials; i++) {
   384→    const wordIndex = i % words.length;
   385→    const colorIndex = (wordIndex + 1 + Math.floor(i / words.length)) % words.length;
   386→    const word = words[wordIndex];
   387→    const color = words[colorIndex];
   388→    
   389→    conditions.push({
   390→      word,
   391→      color,
   392→      colorHex: COLOR_MAP[color as keyof typeof COLOR_MAP],
   393→      congruent: false,
   394→      trialType,
   395→      blockNumber,
   396→      trialNumber: halfTrials + i + 1
   397→    });
   398→  }
   399→  
   400→  // Shuffle conditions for randomization
   401→  return shuffleArray(conditions);
   402→}
   403→
   404→// Helper function to add a Stroop trial to the experiment
   405→function addStroopTrial(
   406→  experimentBuilder: any,
   407→  condition: StroopCondition,
   408→  index: number
   409→) {
   410→  // Fixation cross
   411→  experimentBuilder.trial()
   412→    .stimulus(() => new TextStimulusPixi(
   413→      `fixation-${condition.trialType}-${index}`,
   414→      '+',
   415→      {
   416→        fontSize: 48,
   417→        color: '#FFFFFF',
   418→        position: { x: window.innerWidth / 2, y: window.innerHeight / 2 }
   419→      }
   420→    ))
   421→    .duration(500);
   422→  
   423→  // Stroop stimulus with response collection
   424→  experimentBuilder.trial()
   425→    .stimulus(() => new TextStimulusPixi(
   426→      `stroop-${condition.trialType}-${index}`,
   427→      condition.word,
   428→      {
   429→        fontSize: 72,
   430→        fontWeight: 'bold',
   431→        color: condition.colorHex,
   432→        position: { x: window.innerWidth / 2, y: window.innerHeight / 2 }
   433→      }
   434→    ))
   435→    .response('keyboard', {
   436→      keys: ['r', 'g', 'b', 'y'],
   437→      timeout: 3000,
   438→      recordData: {
   439→        trialType: condition.trialType,
   440→        blockNumber: condition.blockNumber,
   441→        trialNumber: condition.trialNumber,
   442→        word: condition.word,
   443→        color: condition.color,
   444→        congruent: condition.congruent,
   445→        stimulusOnset: Date.now() // For timing validation
   446→      }
   447→    })
   448→    .wait(200); // Inter-trial interval
   449→}
   450→
   451→// Fisher-Yates shuffle
   452→function shuffleArray<T>(array: T[]): T[] {
   453→  const shuffled = [...array];
   454→  for (let i = shuffled.length - 1; i > 0; i--) {
   455→    const j = Math.floor(Math.random() * (i + 1));
   456→    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
   457→  }
   458→  return shuffled;
   459→}
   460→
   461→// Export data in BIDS-compatible format
   462→function exportBIDSData(results: any): string {
   463→  const header = [
   464→    'onset',
   465→    'duration', 
   466→    'trial_type',
   467→    'response_time',
   468→    'response',
   469→    'correct',
   470→    'word',
   471→    'color',
   472→    'congruent',
   473→    'block_number',
   474→    'trial_number'
   475→  ].join('\t');
   476→  
   477→  const rows = results.trials.map((trial: any) => {
   478→    const correct = RESPONSE_MAP[trial.response as keyof typeof RESPONSE_MAP] === trial.color;
   479→    return [
   480→      trial.onset,
   481→      trial.duration,
   482→      trial.trialType,
   483→      trial.responseTime,
   484→      trial.response,
   485→      correct ? 1 : 0,
   486→      trial.word,
   487→      trial.color,
   488→      trial.congruent ? 1 : 0,
   489→      trial.blockNumber,
   490→      trial.trialNumber
   491→    ].join('\t');
   492→  });
   493→  
   494→  return [header, ...rows].join('\n');
   495→}
   496→
   497→// Main execution function
