// Helper function to generate counterbalanced Stroop conditions
function generateStroopConditions(
  numTrials: number, 
  trialType: 'practice' | 'test',
  blockNumber: number
): StroopCondition[] {
  const words = Object.keys(COLOR_MAP);
  const conditions: StroopCondition[] = [];

  // Ensure equal distribution of congruent and incongruent trials
  const halfTrials = Math.floor(numTrials / 2);

  // Generate congruent trials
  for (let i = 0; i < halfTrials; i++) {
    const wordIndex = i % words.length;
    const word = words[wordIndex];
    conditions.push({
      word,
      color: word,
      colorHex: COLOR_MAP[word as keyof typeof COLOR_MAP],
      congruent: true,
      trialType,
      blockNumber,
      trialNumber: i + 1
    });
  }

  // Generate incongruent trials
  for (let i = 0; i < numTrials - halfTrials; i++) {
    const wordIndex = i % words.length;
    const colorIndex = (wordIndex + 1 + Math.floor(i / words.length)) % words.length;
    const word = words[wordIndex];
    const color = words[colorIndex];

    conditions.push({
      word,
      color,
      colorHex: COLOR_MAP[color as keyof typeof COLOR_MAP],
      congruent: false,
      trialType,
      blockNumber,
      trialNumber: halfTrials + i + 1
    });
  }

  // Shuffle conditions for randomization
  return shuffleArray(conditions);
}

// Helper function to add a Stroop trial to the experiment
function addStroopTrial(
  experimentBuilder: any,
  condition: StroopCondition,
  index: number
) {
  // Fixation cross
  experimentBuilder.trial()
    .stimulus(() => new TextStimulusPixi(
      `fixation-${condition.trialType}-${index}`,
      '+',
      {
        fontSize: 48,
        color: '#FFFFFF',
        position: { x: window.innerWidth / 2, y: window.innerHeight / 2 }
      }
    ))
    .duration(500);

  // Stroop stimulus with response collection
  experimentBuilder.trial()
    .stimulus(() => new TextStimulusPixi(
      `stroop-${condition.trialType}-${index}`,
      condition.word,
      {
        fontSize: 72,
        fontWeight: 'bold',
        color: condition.colorHex,
        position: { x: window.innerWidth / 2, y: window.innerHeight / 2 }
      }
    ))
    .response('keyboard', {
      keys: ['r', 'g', 'b', 'y'],
      timeout: 3000,
      recordData: {
        trialType: condition.trialType,
        blockNumber: condition.blockNumber,
        trialNumber: condition.trialNumber,
        word: condition.word,
        color: condition.color,
        congruent: condition.congruent,
        stimulusOnset: Date.now() // For timing validation
      }
    })
    .wait(200); // Inter-trial interval
}

// Fisher-Yates shuffle
function shuffleArray<T>(array: T[]): T[] {
  const shuffled = [...array];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled;
}

// Export data in BIDS-compatible format
function exportBIDSData(results: any): string {
  const header = [
    'onset',
    'duration', 
    'trial_type',
    'response_time',
    'response',
    'correct',
    'word',
    'color',
    'congruent',
    'block_number',
    'trial_number'
  ].join('\t');

  const rows = results.trials.map((trial: any) => {
    const correct = RESPONSE_MAP[trial.response as keyof typeof RESPONSE_MAP] === trial.color;
    return [
      trial.onset,
      trial.duration,
      trial.trialType,
      trial.responseTime,
      trial.response,
      correct ? 1 : 0,
      trial.word,
      trial.color,
      trial.congruent ? 1 : 0,
      trial.blockNumber,
      trial.trialNumber
    ].join('\t');
  });

  return [header, ...rows].join('\n');
}

// Main execution function
async function runCompleteStroopTask() {
  try {
