/**
 * BIDS-compatible Data Schema for Psycho-Forge
 * 
 * This module defines the canonical data export schema that ensures
 * BIDS (Brain Imaging Data Structure) compatibility for behavioral data.
 * 
 * BIDS specification for behavioral data:
 * https://bids-specification.readthedocs.io/en/stable/modality-specific-files/behavioral-data.html
 * 
 * @module BIDSDataSchema
 * @version 0.1.0
 */

import { z } from 'zod';

/**
 * BIDS event file schema
 * Required columns: onset, duration
 * Recommended: trial_type, response_time, stim_file
 */
export const BIDSEventSchema = z.object({
  // Required BIDS columns
  onset: z.number().describe('Onset time of the event in seconds relative to the start of the acquisition'),
  duration: z.number().describe('Duration of the event in seconds'),

  // Highly recommended columns
  trial_type: z.string().optional().describe('Primary categorization of the trial'),
  response_time: z.number().optional().describe('Response time in seconds from stimulus onset'),
  stim_file: z.string().optional().describe('Path or name of the stimulus file'),

  // Response information
  response: z.string().optional().describe('The actual response made by the participant'),
  accuracy: z.number().min(0).max(1).optional().describe('Response accuracy (0=incorrect, 1=correct)'),

  // Additional experimental columns
  trial_index: z.number().int().min(0).optional().describe('Trial number within the experiment'),
  block_index: z.number().int().min(0).optional().describe('Block number within the experiment'),
  condition: z.string().optional().describe('Experimental condition'),

  // Stimulus properties
  stim_type: z.string().optional().describe('Type of stimulus (text, image, audio, video)'),
  stim_duration: z.number().optional().describe('Intended duration of stimulus presentation'),

  // Technical information
  timestamp: z.number().optional().describe('High-precision timestamp from experiment clock'),
  frame_presented: z.number().int().optional().describe('Frame number when stimulus was presented'),

  // Metadata
  metadata: z.record(z.unknown()).optional().describe('Additional experiment-specific metadata')
});

export type BIDSEvent = z.infer<typeof BIDSEventSchema>;

/**
 * Participant information schema (participants.tsv)
 */
export const BIDSParticipantSchema = z.object({
  participant_id: z.string().regex(/^sub-[a-zA-Z0-9]+$/).describe('BIDS participant identifier'),
  age: z.number().optional().describe('Age of participant in years'),
  sex: z.enum(['male', 'female', 'other']).optional().describe('Biological sex'),
  handedness: z.enum(['left', 'right', 'ambidextrous']).optional().describe('Dominant hand'),
  group: z.string().optional().describe('Experimental group assignment'),
  session_count: z.number().int().min(1).optional().describe('Number of sessions completed')
});

export type BIDSParticipant = z.infer<typeof BIDSParticipantSchema>;

/**
 * Session information schema
 */
export const BIDSSessionSchema = z.object({
  session_id: z.string().regex(/^ses-[a-zA-Z0-9]+$/).describe('BIDS session identifier'),
  date: z.string().describe('Session date in YYYY-MM-DD format'),
  time: z.string().optional().describe('Session start time in HH:MM:SS format'),
  experimenter: z.string().optional().describe('Name or ID of experimenter'),
  lab: z.string().optional().describe('Laboratory or testing location'),
  notes: z.string().optional().describe('Session notes')
});

export type BIDSSession = z.infer<typeof BIDSSessionSchema>;

/**
 * Task metadata schema (*_task.json)
 */
export const BIDSTaskMetadataSchema = z.object({
  TaskName: z.string().describe('Name of the task'),
  TaskDescription: z.string().optional().describe('Longer description of the task'),
  TaskVersion: z.string().describe('Version of the task implementation'),

  // Timing information
  SamplingFrequency: z.number().optional().describe('Sampling frequency in Hz'),
  StartTime: z.number().optional().describe('Start time of the task relative to session start'),

  // Response information
  ResponseOptions: z.array(z.string()).optional().describe('List of possible responses'),
  ResponseUnit: z.string().optional().describe('Unit of response time measurements'),

  // Instructions
  Instructions: z.string().optional().describe('Task instructions given to participants'),

  // References
  CogAtlasID: z.string().optional().describe('Cognitive Atlas task ID'),
  CogPOID: z.string().optional().describe('Cognitive Paradigm Ontology ID'),
  ReferencesAndLinks: z.array(z.string()).optional().describe('DOIs or URLs for references')
});

export type BIDSTaskMetadata = z.infer<typeof BIDSTaskMetadataSchema>;

/**
 * Complete experimental data export schema
 */
export const PsyforgeDataExportSchema = z.object({
  // Schema versioning
  schemaVersion: z.literal('0.1.0').describe('Version of the data schema'),
  exportVersion: z.string().describe('Version of the export tool'),
  exportDate: z.string().describe('Export timestamp in ISO 8601 format'),

  // Experiment information
  experiment: z.object({
    name: z.string(),
    version: z.string(),
    description: z.string().optional(),
    doi: z.string().optional(),
    author: z.string().optional(),
    institution: z.string().optional()
  }),

  // Platform information
  platform: z.object({
    name: z.literal('Psycho-Forge'),
    version: z.string(),
    userAgent: z.string(),
    screenResolution: z.object({
      width: z.number(),
      height: z.number()
    }),
    devicePixelRatio: z.number(),
    refreshRate: z.number().optional()
  }),

  // Participant information
  participant: BIDSParticipantSchema.partial().extend({
    participant_id: z.string() // Allow non-BIDS format for flexibility
  }),

  // Session information
  session: BIDSSessionSchema.partial().extend({
    session_id: z.string() // Allow non-BIDS format for flexibility
  }),

  // Events data (main trial data)
  events: z.array(BIDSEventSchema),

  // Summary statistics
  summary: z.object({
    totalTrials: z.number(),
    completedTrials: z.number(),
    totalDuration: z.number().describe('Total experiment duration in seconds'),
    overallAccuracy: z.number().min(0).max(1).optional(),
    meanResponseTime: z.number().optional(),
    blockCount: z.number().optional()
  }),

  // Quality metrics
  quality: z.object({
    missedFrames: z.number().optional().describe('Number of missed display frames'),
    timingPrecision: z.number().optional().describe('Estimated timing precision in ms'),
    droppedResponses: z.number().optional().describe('Number of responses that failed to register')
  }).optional(),

  // Custom data (for non-standard measurements)
  customData: z.record(z.unknown()).optional()
});

export type PsyforgeDataExport = z.infer<typeof PsyforgeDataExportSchema>;

/**
 * Data transformer to convert internal format to BIDS format
 */
export class BIDSDataTransformer {
  /**
   * Convert Psycho-Forge internal data to BIDS-compatible format
   */
  static toBIDS(data: PsyforgeDataExport): {
    events: BIDSEvent[];
    participants: BIDSParticipant;
    sessions: BIDSSession;
    taskMetadata: BIDSTaskMetadata;
  } {
    // Transform events to strict BIDS format
    const bidsEvents = data.events.map(event => ({
      onset: event.onset,
      duration: event.duration,
      trial_type: event.trial_type,
      response_time: event.response_time,
      stim_file: event.stim_file,
      response: event.response,
      accuracy: event.accuracy,
      // Additional columns are allowed in BIDS
      trial_index: event.trial_index,
      block_index: event.block_index,
      condition: event.condition
    }));

    // Create BIDS participant entry
    const participant: BIDSParticipant = {
      participant_id: data.participant.participant_id.startsWith('sub-') 
        ? data.participant.participant_id 
        : `sub-${data.participant.participant_id}`,
      age: data.participant.age,
      sex: data.participant.sex as 'male' | 'female' | 'other' | undefined,
      handedness: data.participant.handedness as 'left' | 'right' | 'ambidextrous' | undefined,
      group: data.participant.group
    };

    // Create BIDS session entry
    const session: BIDSSession = {
      session_id: data.session.session_id.startsWith('ses-')
        ? data.session.session_id
        : `ses-${data.session.session_id}`,
      date: data.session.date || new Date().toISOString().split('T')[0],
      time: data.session.time,
      experimenter: data.session.experimenter,
      lab: data.session.lab,
      notes: data.session.notes
    };

    // Create task metadata
    const taskMetadata: BIDSTaskMetadata = {
      TaskName: data.experiment.name,
      TaskDescription: data.experiment.description,
      TaskVersion: data.experiment.version,
      SamplingFrequency: data.platform.refreshRate,
      ResponseUnit: 'seconds',
      ReferencesAndLinks: data.experiment.doi ? [data.experiment.doi] : undefined
    };

    return {
      events: bidsEvents,
      participants: participant,
      sessions: session,
      taskMetadata
    };
  }

  /**
   * Validate data against BIDS schema
   */
  static validate(data: unknown): PsyforgeDataExport {
    return PsyforgeDataExportSchema.parse(data);
  }

  /**
   * Export data in various formats
   */
  static export(data: PsyforgeDataExport, format: 'json' | 'csv' | 'tsv' = 'json'): string {
    switch (format) {
      case 'json':
        return JSON.stringify(data, null, 2);

      case 'csv':
      case 'tsv': {
        const delimiter = format === 'csv' ? ',' : '\t';
        const events = data.events;

        if (events.length === 0) return '';

        // Get all unique keys from events
        const keys = Array.from(new Set(
          events.flatMap(event => Object.keys(event))
        )).filter(key => key !== 'metadata'); // Exclude complex objects

        // Create header
        const header = keys.join(delimiter);

        // Create rows
        const rows = events.map(event => 
          keys.map(key => {
            const value = (event as any)[key];
            if (value === undefined || value === null) return '';
            if (typeof value === 'string' && value.includes(delimiter)) {
              return `"${value.replace(/"/g, '""')}"`;
            }
            return String(value);
          }).join(delimiter)
        );

        return [header, ...rows].join('\n');
      }

      default:
        throw new Error(`Unsupported export format: ${format}`);
    }
  }
}

/**
 * Schema migration utilities
 */
export class DataSchemaMigration {
  private static migrations: Map<string, (data: any) => any> = new Map();

  /**
   * Register a migration from one schema version to another
   */
  static registerMigration(fromVersion: string, toVersion: string, migration: (data: any) => any): void {
    const key = `${fromVersion}->${toVersion}`;
    this.migrations.set(key, migration);
  }

  /**
   * Migrate data from one schema version to another
   */
  static migrate(data: any, targetVersion: string = '0.1.0'): PsyforgeDataExport {
    const currentVersion = data.schemaVersion || '0.0.0';

    if (currentVersion === targetVersion) {
      return BIDSDataTransformer.validate(data);
    }

    const migrationKey = `${currentVersion}->${targetVersion}`;
    const migration = this.migrations.get(migrationKey);

    if (!migration) {
      throw new Error(`No migration path from version ${currentVersion} to ${targetVersion}`);
    }

    const migratedData = migration(data);
    return BIDSDataTransformer.validate(migratedData);
  }
}

// Export convenience functions
export function createDataExport(
  experiment: PsyforgeDataExport['experiment'],
  events: BIDSEvent[],
  options: Partial<PsyforgeDataExport> = {}
): PsyforgeDataExport {
  const now = new Date();

  return {
    schemaVersion: '0.1.0',
    exportVersion: '1.0.0',
    exportDate: now.toISOString(),
    experiment,
    platform: {
      name: 'Psycho-Forge',
      version: '1.0.0',
      userAgent: typeof navigator !== 'undefined' ? navigator.userAgent : 'Unknown',
      screenResolution: {
        width: typeof window !== 'undefined' ? window.screen.width : 0,
        height: typeof window !== 'undefined' ? window.screen.height : 0
      },
      devicePixelRatio: typeof window !== 'undefined' ? window.devicePixelRatio : 1,
      refreshRate: undefined // Would need to be measured
    },
    participant: {
      participant_id: 'unknown'
    },
    session: {
      session_id: '001',
      date: now.toISOString().split('T')[0]
    },
    events,
    summary: {
      totalTrials: events.length,
      completedTrials: events.filter(e => e.response !== undefined).length,
      totalDuration: events.length > 0 
        ? Math.max(...events.map(e => e.onset + e.duration))
        : 0,
      overallAccuracy: events.length > 0
        ? events.filter(e => e.accuracy !== undefined).reduce((sum, e) => sum + (e.accuracy || 0), 0) / events.filter(e => e.accuracy !== undefined).length
        : undefined,
      meanResponseTime: events.length > 0
        ? events.filter(e => e.response_time !== undefined).reduce((sum, e) => sum + (e.response_time || 0), 0) / events.filter(e => e.response_time !== undefined).length
        : undefined
    },
    ...options
  };
}

